"""MKT John chapters 16-21."""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent
DRAFT = ROOT / 'data' / 'translation' / 'draft'

def load(tier, book):
    p = DRAFT / tier / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save(tier, book, data):
    p = DRAFT / tier / f'{book}.json'
    p.write_text(json.dumps(data, ensure_ascii=False))
    print(f'  wrote {p.relative_to(ROOT)}')

JOHN = {
  "16": {
    "1": {"L":"'These things I have spoken to you so that you will not be caused to stumble.'","M":"'All this I have told you so that you will not fall away.'","T":"'I have told you all this so that you won't lose your faith.'"},
    "2": {"L":"'They will put you out of the synagogues; but an hour is coming when everyone who kills you will think he is offering worship to God.'","M":"'They will put you out of the synagogue; in fact, the time is coming when anyone who kills you will think they are offering a service to God.'","T":"'You will be expelled from the synagogues. In fact, the time is coming when anyone who kills you will think they are doing God a favor.'"},
    "3": {"L":"'And they will do these things because they have not known the Father or me.'","M":"'They will do such things because they have not known the Father or me.'","T":"'They will do these things because they have never truly known the Father or me.'"},
    "4": {"L":"'But I have spoken these things to you so that when their hour comes, you may remember that I told you about them. And these things I did not say to you from the beginning, because I was with you.'","M":"'I have told you this, so that when their time comes you will remember that I warned you about them. I did not tell you this from the beginning because I was with you,'","T":"'I have told you in advance so that when it happens you will remember I warned you. I didn't tell you this at the start because I was still with you.'"},
    "5": {"L":"'but now I am going to the one who sent me; and none of you asks me: Where are you going?'","M":"'but now I am going to him who sent me. None of you asks me, Where are you going?'","T":"'But now I am returning to the one who sent me—and none of you asks me where I'm going.'"},
    "6": {"L":"'But because I have said these things to you, sorrow has filled your heart.'","M":"'Rather, you are filled with grief because I have said these things.'","T":"'Instead, your hearts are full of grief because I've told you all this.'"},
    "7": {"L":"'But I tell you the truth: it is to your advantage that I go away; for if I do not go away, the Helper will not come to you; but if I go, I will send him to you.'","M":"'But very truly I tell you, it is for your good that I am going away. Unless I go away, the Advocate will not come to you; but if I go, I will send him to you.'","T":"'But I tell you the truth: it is actually better for you that I go away. If I don't go, the Advocate won't come. But if I go, I will send him to you.'"},
    "8": {"L":"'And when that one comes, he will convict the world concerning sin and concerning righteousness and concerning judgment:'","M":"'When he comes, he will prove the world to be in the wrong about sin and righteousness and judgment:'","T":"'When he comes, he will convict the world about sin, righteousness, and judgment:'"},
    "9": {"L":"'concerning sin, because they do not believe in me;'","M":"'about sin, because people do not believe in me;'","T":"'about sin—because they refuse to believe in me;'"},
    "10": {"L":"'concerning righteousness, because I am going to the Father and you will no longer see me;'","M":"'about righteousness, because I am going to the Father, where you can see me no longer;'","T":"'about righteousness—because I am going to the Father, and you will see me no more;'"},
    "11": {"L":"'concerning judgment, because the ruler of this world has been judged.'","M":"'and about judgment, because the prince of this world now stands condemned.'","T":"'about judgment—because the ruler of this world has already been condemned.'"},
    "12": {"L":"'I still have many things to say to you, but you are not able to bear them now.'","M":"'I have much more to say to you, more than you can now bear.'","T":"'There is so much more I want to tell you, but you can't handle it right now.'"},
    "13": {"L":"'But when that one—the Spirit of truth—comes, he will guide you in all the truth; for he will not speak from himself, but whatever he hears he will speak; and he will announce to you the things that are coming.'","M":"'But when he, the Spirit of truth, comes, he will guide you into all the truth. He will not speak on his own; he will speak only what he hears, and he will tell you what is yet to come.'","T":"'But when the Spirit of truth comes, he will guide you into all truth. He won't speak on his own authority—he will speak what he hears, and he will reveal what is to come.'"},
    "14": {"L":"'He will glorify me, because he will take from what is mine and announce it to you.'","M":"'He will glorify me because it is from me that he will receive what he will make known to you.'","T":"'He will bring glory to me because he will take what is mine and make it known to you.'"},
    "15": {"L":"'All things that the Father has are mine; for this reason I said that he takes from what is mine and will announce it to you.'","M":"'All that belongs to the Father is mine. That is why I said the Spirit will receive from me what he will make known to you.'","T":"'Everything the Father has belongs to me. That is why I said the Spirit will take what is mine and reveal it to you.'"},
    "16": {"L":"'A little while, and you will no longer see me; and again a little while, and you will see me.'","M":"'In a little while you will see me no more, and then after a little while you will see me.'","T":"'In a little while you will no longer see me; then after a little while you will see me again.'"},
    "17": {"L":"Therefore some of his disciples said to one another: 'What is this that he says to us: A little while, and you will not see me; and again a little while, and you will see me? And: Because I am going to the Father?'","M":"At this, some of his disciples said to one another, 'What does he mean by saying, In a little while you will see me no more, and then after a little while you will see me, and Because I am going to the Father?'","T":"Some of his disciples were whispering to each other, 'What does he mean by all this talk about a little while? And going to the Father?'"},
    "18": {"L":"So they were saying: 'What is this that he says: A little while? We do not know what he is saying.'","M":"They kept asking, 'What does he mean by a little while? We don't understand what he is saying.'","T":"'We can't figure out what he's talking about,' they said."},
    "19": {"L":"Jesus knew that they wanted to ask him, and said to them: 'Are you inquiring among yourselves about this, that I said: A little while, and you will not see me; and again a little while, and you will see me?'","M":"Jesus saw that they wanted to ask him about this, so he said to them, 'Are you asking one another what I meant when I said, In a little while you will see me no more, and then after a little while you will see me?'","T":"Jesus knew they wanted to ask him about this, so he said, 'Are you trying to figure out what I meant when I said you would see me for a little while and then not see me?'"},
    "20": {"L":"'Truly, truly I say to you, you will weep and lament, but the world will rejoice; you will grieve, but your grief will turn to joy.'","M":"'Truly, truly, I tell you, you will weep and mourn while the world rejoices. You will grieve, but your grief will turn to joy.'","T":"'I tell you the truth—you will weep and grieve while the world celebrates. But your sorrow will turn into joy.'"},
    "21": {"L":"'When a woman is in labor she has sorrow, because her hour has come; but when she has given birth to the child, she no longer remembers the anguish because of the joy that a person has been born into the world.'","M":"'A woman giving birth to a child has pain because her time has come; but when her baby is born she forgets the anguish because of her joy that a child is born into the world.'","T":"'A woman in labor goes through anguish while giving birth. But once the baby arrives, she forgets the pain because of the joy that a new person has come into the world.'"},
    "22": {"L":"'So you too are now in sorrow; but I will see you again and your heart will rejoice, and no one will take your joy from you.'","M":"'So with you: Now is your time of grief, but I will see you again and you will rejoice, and no one will take away your joy.'","T":"'You have sorrow now, but I will see you again. Then your hearts will be filled with joy that no one can take away.'"},
    "23": {"L":"'And in that day you will ask me nothing. Truly, truly I say to you, whatever you ask the Father in my name, he will give you.'","M":"'In that day you will no longer ask me anything. Truly, truly, I tell you, my Father will give you whatever you ask in my name.'","T":"'When that day comes, you won't need to ask me for anything. I tell you the truth: whatever you ask the Father in my name, he will give you.'"},
    "24": {"L":"'Until now you have asked nothing in my name. Ask and you will receive, so that your joy may be made full.'","M":"'Until now you have not asked for anything in my name. Ask and you will receive, and your joy will be complete.'","T":"'You have not been asking in my name. Start asking! Ask and you will receive, so that your joy will be completely full.'"},
    "25": {"L":"'These things I have spoken to you in figures of speech; an hour is coming when I will no longer speak to you in figures of speech, but I will announce to you plainly about the Father.'","M":"'Though I have been speaking figuratively, a time is coming when I will no longer use this kind of language but will tell you plainly about my Father.'","T":"'I have been speaking in illustrations, but the time is coming when I will speak plainly about the Father—no more veiled language.'"},
    "26": {"L":"'In that day you will ask in my name; and I do not say to you that I will ask the Father on your behalf;'","M":"'In that day you will ask in my name. I am not saying that I will ask the Father on your behalf;'","T":"'When that day comes, you will ask directly in my name. I am not saying that I will intercede for you—'"},
    "27": {"L":"'for the Father himself loves you, because you have loved me and have believed that I came from God.'","M":"'No, the Father himself loves you because you have loved me and have believed that I came from God.'","T":"'The Father himself loves you because you have loved me and believed that I came from God.'"},
    "28": {"L":"'I came from the Father and have come into the world; again I am leaving the world and going to the Father.'","M":"'I came from the Father and entered the world; now I am leaving the world and going back to the Father.'","T":"'I came from the Father into the world. Now I am leaving the world and returning to the Father.'"},
    "29": {"L":"His disciples say: 'Look, now you are speaking plainly, and are saying no figure of speech!'","M":"Then Jesus' disciples said, 'Now you are speaking clearly and without figures of speech.'","T":"His disciples said, 'Now you're speaking plainly—no more veiled language!'"},
    "30": {"L":"'Now we know that you know all things and have no need for anyone to ask you; by this we believe that you came from God.'","M":"'Now we can see that you know all things and that you do not even need to have anyone ask you questions. This makes us believe that you came from God.'","T":"'Now we know that you know everything, and you don't need anyone to question you. This makes us believe you truly came from God.'"},
    "31": {"L":"Jesus answered them: 'Do you now believe?'","M":"'Do you now believe?' Jesus replied.","T":"'So now you believe?' Jesus replied."},
    "32": {"L":"'Look, an hour is coming, and has already come, when you will be scattered each to his own home, and you will leave me alone. And yet I am not alone, because the Father is with me.'","M":"'A time is coming and in fact has come when you will be scattered, each to your own home. You will leave me all alone. Yet I am not alone, for my Father is with me.'","T":"'The hour is coming—and has already arrived—when you will all scatter to your own homes and leave me alone. Yet I am not alone, because the Father is with me.'"},
    "33": {"L":"'These things I have spoken to you so that in me you may have peace. In the world you have tribulation; but take courage—I have overcome the world.'","M":"'I have told you these things, so that in me you may have peace. In this world you will have trouble. But take heart! I have overcome the world.'","T":"'I have told you all this so that in me you can find peace. You will have trouble in this world—but take courage! I have conquered the world.'"}
  },

  "17": {
    "1": {"L":"These things Jesus spoke, and lifting up his eyes to heaven, he said: 'Father, the hour has come; glorify your Son, so that the Son may glorify you,'","M":"After Jesus said this, he looked toward heaven and prayed: 'Father, the hour has come. Glorify your Son, that your Son may glorify you.'","T":"After saying all this, Jesus looked up to heaven and prayed: 'Father, the time has come. Bring glory to your Son, so the Son can bring glory to you.'"},
    "2": {"L":"'even as you gave him authority over all flesh, so that everything you have given him he may give them eternal life.'","M":"'For you granted him authority over all people that he might give eternal life to all those you have given him.'","T":"'For you have given him authority over everyone so he can give eternal life to all those you gave him.'"},
    "3": {"L":"'And this is eternal life: that they know you, the only true God, and Jesus Christ whom you sent.'","M":"'Now this is eternal life: that they know you, the only true God, and Jesus Christ, whom you have sent.'","T":"'And eternal life is this: to know you, the one true God, and Jesus Christ, the one you sent.'"},
    "4": {"L":"'I glorified you on the earth, having finished the work that you gave me to do.'","M":"'I have brought you glory on earth by finishing the work you gave me to do.'","T":"'I brought glory to you here on earth by completing the work you gave me to do.'"},
    "5": {"L":"'And now, Father, glorify me beside yourself with the glory that I had with you before the world existed.'","M":"'And now, Father, glorify me in your presence with the glory I had with you before the world began.'","T":"'Now, Father, bring me back into your glory—the glory I shared with you before the world existed.'"},
    "6": {"L":"'I revealed your name to the men whom you gave me out of the world. They were yours, and you gave them to me, and they have kept your word.'","M":"'I have revealed you to those whom you gave me out of the world. They were yours; you gave them to me and they have obeyed your word.'","T":"'I have revealed who you are to the people you gave me from this world. They were yours, and you gave them to me, and they have obeyed your word.'"},
    "7": {"L":"'Now they have come to know that everything you have given me is from you.'","M":"'Now they know that everything you have given me comes from you.'","T":"'Now they know that everything I have is a gift from you.'"},
    "8": {"L":"'Because the words that you gave me I have given to them; and they received them and have truly known that I came from you; and they believed that you sent me.'","M":"'For I gave them the words you gave me and they accepted them. They knew with certainty that I came from you, and they believed that you sent me.'","T":"'I have given them the words you gave me, and they accepted them. They know with certainty that I came from you, and they believe you sent me.'"},
    "9": {"L":"'I pray for them; I do not pray for the world, but for those whom you have given me, for they are yours.'","M":"'I pray for them. I am not praying for the world, but for those you have given me, for they are yours.'","T":"'I am praying for them. I am not praying for the world at large, but for those you gave me—for they belong to you.'"},
    "10": {"L":"'And all things that are mine are yours, and yours are mine; and I have been glorified in them.'","M":"'All I have is yours, and all you have is mine. And glory has come to me through them.'","T":"'Everything of mine is yours, and everything of yours is mine. And I have been glorified through them.'"},
    "11": {"L":"'And I am no longer in the world, and they are in the world, and I am coming to you. Holy Father, keep them in your name, which you have given me, so that they may be one just as we are one.'","M":"'I will remain in the world no longer, but they are still in the world, and I am coming to you. Holy Father, protect them by the power of your name, the name you gave me, so that they may be one as we are one.'","T":"'I am about to leave the world, but they must remain in the world. Holy Father, keep them safe through the power of your name—the name you gave me—so they can be united just as we are.'"},
    "12": {"L":"'While I was with them, I was keeping them in your name, which you have given me; and I guarded them, and not one of them perished except the son of destruction, so that the scripture might be fulfilled.'","M":"'While I was with them, I protected them and kept them safe by that name you gave me. None has been lost except the one doomed to destruction so that Scripture would be fulfilled.'","T":"'During my time with them, I kept them safe in your name. None was lost except the one destined for destruction—fulfilling what scripture said.'"},
    "13": {"L":"'But now I am coming to you; and these things I speak in the world so that they may have my joy fulfilled in themselves.'","M":"'I am coming to you now, but I say these things while I am still in the world, so that they may have the full measure of my joy within them.'","T":"'But now I am coming to you, and I say these things while still in the world so they can experience my complete joy within them.'"},
    "14": {"L":"'I have given them your word, and the world hated them, because they are not of the world, just as I am not of the world.'","M":"'I have given them your word and the world has hated them, for they are not of the world any more than I am of the world.'","T":"'I have given them your word, and the world has hated them because they don't belong to the world system—just as I don't.'"},
    "15": {"L":"'I do not ask that you take them out of the world, but that you keep them from the evil one.'","M":"'My prayer is not that you take them out of the world but that you protect them from the evil one.'","T":"'I'm not asking you to remove them from the world, but to keep them safe from the evil one.'"},
    "16": {"L":"'They are not of the world, just as I am not of the world.'","M":"'They are not of the world, even as I am not of it.'","T":"'They don't belong to this world system, just as I don't.'"},
    "17": {"L":"'Sanctify them in the truth; your word is truth.'","M":"'Sanctify them by the truth; your word is truth.'","T":"'Make them holy through your truth—your word is truth.'"},
    "18": {"L":"'As you sent me into the world, I also sent them into the world.'","M":"'As you sent me into the world, I have sent them into the world.'","T":"'Just as you sent me into the world, I am sending them into the world.'"},
    "19": {"L":"'And for their sake I sanctify myself, so that they themselves also may be sanctified in truth.'","M":"'For them I sanctify myself, that they too may be truly sanctified.'","T":"'And I give myself completely to your purpose so that they also can be truly made holy.'"},
    "20": {"L":"'And not for these only do I pray, but also for those who believe in me through their word;'","M":"'My prayer is not for them alone. I pray also for those who will believe in me through their message,'","T":"'I am not praying only for these disciples. I am also praying for all who will believe in me because of their testimony.'"},
    "21": {"L":"'that they all may be one, just as you, Father, are in me and I in you—that they also may be in us, so that the world may believe that you sent me.'","M":"'that all of them may be one, Father, just as you are in me and I am in you. May they also be in us so that the world may believe that you have sent me.'","T":"'I pray that they will all be one—just as you and I are one. As you are in me and I am in you, may they be in us—so the world will believe you sent me.'"},
    "22": {"L":"'And the glory that you have given me I have given them, so that they may be one just as we are one—'","M":"'I have given them the glory that you gave me, that they may be one as we are one—'","T":"'I have given them the same glory you gave me, so they may be united as we are united—'"},
    "23": {"L":"'I in them and you in me, so that they may be made perfect in one, and so that the world may know that you sent me and loved them as you loved me.'","M":"'I in them and you in me—so that they may be brought to complete unity. Then the world will know that you sent me and have loved them even as you have loved me.'","T":"'I in them and you in me—so they may be brought into complete unity. Then the world will know that you sent me and that you love them as much as you love me.'"},
    "24": {"L":"'Father, what you have given me, I desire that they also may be with me where I am, so that they may see my glory that you gave me, because you loved me before the foundation of the world.'","M":"'Father, I want those you have given me to be with me where I am, and to see my glory, the glory you have given me because you loved me before the creation of the world.'","T":"'Father, I want those you gave me to be with me where I am, and to see my glory—the glory you gave me because you loved me before the world was created.'"},
    "25": {"L":"'O righteous Father, the world did not know you, but I knew you; and these have come to know that you sent me.'","M":"'Righteous Father, though the world does not know you, I know you, and they know that you have sent me.'","T":"'Righteous Father, the world doesn't know you, but I know you—and these disciples know you sent me.'"},
    "26": {"L":"'And I made known to them your name, and I will make it known, so that the love with which you have loved me may be in them, and I in them.'","M":"'I have made you known to them, and will continue to make you known in order that the love you have for me may be in them and that I myself may be in them.'","T":"'I have revealed your name to them, and I will continue to do so—so that your love for me may live in them, and I myself will be in them.'"}
  },

  "18": {
    "1": {"L":"Having said these things, Jesus went out with his disciples across the Kidron Valley, where there was a garden, into which he and his disciples entered.","M":"When he had finished praying, Jesus left with his disciples and crossed the Kidron Valley. On the other side there was a garden, and he and his disciples went into it.","T":"After Jesus had said all this, he went with his disciples across the Kidron Valley to a garden on the other side."},
    "2": {"L":"Now Judas, who was betraying him, also knew the place, because Jesus had often met there with his disciples.","M":"Now Judas, who betrayed him, knew the place, because Jesus had often met there with his disciples.","T":"Judas, who would betray him, knew the place well—Jesus had often gone there with his disciples."},
    "3": {"L":"So Judas, having taken the cohort and officers from the chief priests and the Pharisees, comes there with lanterns and torches and weapons.","M":"So Judas came to the garden, guiding a detachment of soldiers and some officials from the chief priests and the Pharisees. They were carrying torches, lanterns and weapons.","T":"Judas arrived with a Roman detachment of soldiers and temple police sent by the chief priests and Pharisees. They were carrying torches, lanterns, and weapons."},
    "4": {"L":"Therefore Jesus, knowing all the things coming upon him, went out and says to them: 'Whom are you seeking?'","M":"Jesus, knowing all that was going to happen to him, went out and asked them, 'Who is it you want?'","T":"Jesus, fully knowing everything that was about to happen to him, stepped forward and asked, 'Who are you looking for?'"},
    "5": {"L":"They answered him: 'Jesus the Nazarene.' He says to them: 'I am.' Now Judas, who was betraying him, was also standing with them.","M":"'Jesus of Nazareth,' they replied. 'I am he,' Jesus said. (And Judas the traitor was standing there with them.)","T":"'Jesus of Nazareth,' they replied. 'I am he,' Jesus said. (Judas, the traitor, was standing there with them.)"},
    "6": {"L":"Therefore when he said to them: 'I am,' they went back and fell to the ground.","M":"When Jesus said, 'I am he,' they drew back and fell to the ground.","T":"When Jesus said 'I am he,' they all stumbled backward and fell to the ground."},
    "7": {"L":"Then he asked them again: 'Whom are you seeking?' And they said: 'Jesus the Nazarene.'","M":"Again he asked them, 'Who is it you want?' They said, 'Jesus of Nazareth.'","T":"Again he asked them, 'Who are you looking for?' 'Jesus of Nazareth,' they said."},
    "8": {"L":"Jesus answered: 'I told you that I am. If therefore you seek me, let these go.'","M":"'I told you that I am he,' Jesus answered. 'If you are looking for me, then let these men go.'","T":"'I told you I am he,' Jesus said. 'If I'm the one you want, let these others go free.'"},
    "9": {"L":"This was to fulfill the word that he had spoken: 'Of those you have given me, I lost none of them.'","M":"This happened so that the words he had spoken would be fulfilled: 'I have not lost one of those you gave me.'","T":"This fulfilled what he had said: 'I have not lost a single one of those you gave me.'"},
    "10": {"L":"Then Simon Peter, having a sword, drew it and struck the high priest's servant and cut off his right ear. The servant's name was Malchus.","M":"Then Simon Peter, who had a sword, drew it and struck the high priest's servant, cutting off his right ear. The servant's name was Malchus.","T":"Simon Peter suddenly drew a sword and struck the high priest's servant, cutting off his right ear. The servant's name was Malchus."},
    "11": {"L":"Therefore Jesus said to Peter: 'Put the sword into the sheath. The cup that the Father has given me—shall I not drink it?'","M":"Jesus commanded Peter, 'Put your sword away! Shall I not drink the cup the Father has given me?'","T":"Jesus told Peter, 'Put your sword away. Should I not drink the cup the Father has given me?'"},
    "12": {"L":"So the cohort and the commander and the officers of the Jews seized Jesus and bound him,","M":"Then the detachment of soldiers with its commander and the Jewish officials arrested Jesus. They bound him","T":"The soldiers, their commander, and the temple police then arrested Jesus and tied him up."},
    "13": {"L":"and led him first to Annas; for he was the father-in-law of Caiaphas, who was high priest that year.","M":"and brought him first to Annas, who was the father-in-law of Caiaphas, the high priest that year.","T":"They took him first to Annas—the father-in-law of Caiaphas, who was high priest that year."},
    "14": {"L":"Now Caiaphas was the one who had advised the Jews that it was to their advantage for one man to die on behalf of the people.","M":"Caiaphas was the one who had advised the Jewish leaders that it would be good if one man died for the people.","T":"This was the same Caiaphas who had told the Jewish leaders, 'It's better for one man to die for the people.'"},
    "15": {"L":"Now Simon Peter was following Jesus, as was another disciple. And that disciple was known to the high priest, and he entered with Jesus into the court of the high priest.","M":"Simon Peter and another disciple were following Jesus. Because this disciple was known to the high priest, he went with Jesus into the high priest's courtyard,","T":"Simon Peter and another disciple followed Jesus. Since that other disciple was known to the high priest, he was allowed into the courtyard with Jesus."},
    "16": {"L":"But Peter was standing at the door outside. So the other disciple, who was known to the high priest, went out and spoke to the doorkeeper and brought Peter in.","M":"but Peter had to wait outside at the door. The other disciple, who was known to the high priest, came back, spoke to the servant girl on duty there and brought Peter in.","T":"Peter stood outside the gate. The other disciple—the one the high priest knew—came back out, spoke to the girl at the gate, and got Peter admitted."},
    "17": {"L":"Therefore the servant girl who was the doorkeeper says to Peter: 'Are you not also one of this man's disciples?' That one says: 'I am not.'","M":"'You aren't one of this man's disciples too, are you?' she asked Peter. He replied, 'I am not.'","T":"The girl at the gate said to Peter, 'You're not one of this man's disciples too, are you?' 'No, I'm not,' Peter replied."},
    "18": {"L":"Now the servants and officers were standing there, having made a charcoal fire, because it was cold, and they were warming themselves; and Peter also was with them, standing and warming himself.","M":"It was cold, and the servants and officials stood around a fire they had made to keep warm. Peter also was standing with them, warming himself.","T":"It was cold, and the servants and police had lit a charcoal fire and were standing around it to keep warm. Peter was standing there with them, warming himself."},
    "19": {"L":"The high priest therefore questioned Jesus about his disciples and about his teaching.","M":"Meanwhile, the high priest questioned Jesus about his disciples and his teaching.","T":"Inside, the high priest questioned Jesus about his disciples and his teaching."},
    "20": {"L":"Jesus answered him: 'I have spoken openly to the world. I always taught in the synagogue and in the temple, where all the Jews come together; and in secret I said nothing.'","M":"'I have spoken openly to the world,' Jesus replied. 'I always taught in synagogues or at the temple, where all the Jews come together. I said nothing in secret.'","T":"Jesus replied, 'I have spoken publicly for everyone to hear. I always taught in the synagogues and in the temple—where all the Jewish people gather. I never said anything in secret.'"},
    "21": {"L":"'Why do you question me? Question those who have heard what I said to them. Look—they know what I said.'","M":"'Why question me? Ask those who heard me. Surely they know what I said.'","T":"'Why are you asking me? Ask those who heard me teach. They know what I said.'"},
    "22": {"L":"When he had said this, one of the officers standing nearby struck Jesus with the palm of his hand, saying: 'Is this how you answer the high priest?'","M":"When Jesus said this, one of the officials nearby slapped him in the face. 'Is this the way you answer the high priest?' he demanded.","T":"One of the officers standing nearby slapped Jesus across the face. 'Is that how you answer the high priest?' he demanded."},
    "23": {"L":"Jesus answered him: 'If I spoke wrongly, testify to the wrong; but if I spoke rightly, why do you strike me?'","M":"'If I said something wrong,' Jesus replied, 'testify as to what is wrong. But if I spoke the truth, why did you strike me?'","T":"Jesus replied, 'If I said something wrong, tell me what it was. But if I told the truth, why are you hitting me?'"},
    "24": {"L":"Annas therefore sent him bound to Caiaphas the high priest.","M":"Then Annas sent him bound to Caiaphas the high priest.","T":"Then Annas sent him, still bound, to Caiaphas the high priest."},
    "25": {"L":"Now Simon Peter was standing and warming himself. So they said to him: 'Are you not also one of his disciples?' He denied it and said: 'I am not.'","M":"Meanwhile, Simon Peter was still standing there warming himself. So they asked him, 'You aren't one of his disciples too, are you?' He denied it, saying, 'I am not.'","T":"Meanwhile, Simon Peter was still standing by the fire, warming himself. Some of them asked him, 'Aren't you one of his disciples too?' He denied it: 'No, I'm not.'"},
    "26": {"L":"One of the servants of the high priest, being a relative of the one whose ear Peter cut off, says: 'Did I not see you in the garden with him?'","M":"One of the high priest's servants, a relative of the man whose ear Peter had cut off, challenged him, 'Didn't I see you with him in the garden?'","T":"But one of the high priest's servants—a relative of the man whose ear Peter had cut off—spoke up: 'Didn't I see you in the garden with him?'"},
    "27": {"L":"Peter therefore denied again; and immediately the rooster crowed.","M":"Again Peter denied it, and at that moment a rooster began to crow.","T":"Peter denied it again—and immediately a rooster crowed."},
    "28": {"L":"Then they lead Jesus from Caiaphas to the Praetorium. Now it was early morning; and they themselves did not enter the Praetorium, so that they would not be defiled, but could eat the Passover.","M":"Then the Jewish leaders took Jesus from Caiaphas to the palace of the Roman governor. By now it was early morning, and to avoid ceremonial uncleanness they did not enter the palace, because they wanted to be able to eat the Passover.","T":"Early in the morning, they took Jesus from Caiaphas to the governor's palace. The Jewish leaders wouldn't go inside because they didn't want to be ritually defiled before eating the Passover meal."},
    "29": {"L":"Therefore Pilate went out to them and says: 'What accusation do you bring against this man?'","M":"So Pilate came out to them and asked, 'What charges are you bringing against this man?'","T":"So Pilate came outside to them and asked, 'What charges are you bringing against this man?'"},
    "30": {"L":"They answered and said to him: 'If this man were not an evildoer, we would not have handed him over to you.'","M":"'If he were not a criminal,' they replied, 'we would not have handed him over to you.'","T":"'If he weren't a criminal,' they snapped, 'we wouldn't have brought him to you.'"},
    "31": {"L":"So Pilate said to them: 'Take him yourselves and judge him according to your law.' The Jews said to him: 'It is not lawful for us to put anyone to death.'","M":"Pilate said, 'Take him yourselves and judge him by your own law.' 'But we have no right to execute anyone,' they objected.","T":"Pilate told them, 'Take him and judge him by your own law.' 'But we don't have the legal authority to execute anyone,' the Jewish leaders replied."},
    "32": {"L":"This was to fulfill the word of Jesus which he spoke, signifying what kind of death he was about to die.","M":"This took place to fulfill what Jesus had said about the kind of death he was going to die.","T":"This was to fulfill what Jesus had said about how he would die."},
    "33": {"L":"Therefore Pilate entered the Praetorium again and called Jesus and said to him: 'Are you the King of the Jews?'","M":"Pilate then went back inside the palace, summoned Jesus and asked him, 'Are you the king of the Jews?'","T":"Pilate went back inside and summoned Jesus. 'Are you the King of the Jews?' he asked."},
    "34": {"L":"Jesus answered: 'Do you say this from yourself, or did others tell you about me?'","M":"'Is that your own idea,' Jesus asked, 'or did others talk to you about me?'","T":"Jesus asked, 'Is that your own question, or did others tell you about me?'"},
    "35": {"L":"Pilate answered: 'I am not a Jew, am I? Your own nation and the chief priests handed you over to me. What have you done?'","M":"'Am I a Jew?' Pilate replied. 'Your own people and chief priests handed you over to me. What is it you have done?'","T":"Pilate replied, 'I'm not a Jew, am I? Your own people and their chief priests handed you over to me. What have you done?'"},
    "36": {"L":"Jesus answered: 'My kingdom is not from this world. If my kingdom were from this world, my servants would have fought to keep me from being handed over to the Jews; but as it is, my kingdom is not from here.'","M":"Jesus said, 'My kingdom is not of this world. If it were, my servants would fight to prevent my arrest by the Jewish leaders. But now my kingdom is from another place.'","T":"Jesus replied, 'My kingdom is not part of this world system. If it were, my followers would have fought to keep me from being handed over. But my kingdom is from another realm entirely.'"},
    "37": {"L":"Therefore Pilate said to him: 'So you are a king?' Jesus answered: 'You say that I am a king. For this I have been born, and for this I have come into the world, so that I should testify to the truth. Everyone who is of the truth hears my voice.'","M":"'You are a king, then!' said Pilate. Jesus answered, 'You say that I am a king. In fact, the reason I was born and came into the world is to testify to the truth. Everyone on the side of truth listens to me.'","T":"'So you are a king!' Pilate said. Jesus replied, 'You're right to call me a king. In fact, I was born and came into the world for this very reason: to testify to the truth. Everyone who belongs to the truth recognizes my voice.'"},
    "38": {"L":"Pilate says to him: 'What is truth?' And having said this he went out again to the Jews and says to them: 'I find no guilt in him.'","M":"'What is truth?' retorted Pilate. With this he went out again to the Jews gathered there and said, 'I find no basis for a charge against him.'","T":"'What is truth?' Pilate muttered. Then he went back out to the crowd. 'I find no basis for a charge against him,' he announced."},
    "39": {"L":"'But you have a custom that I release one to you at the Passover. Do you will therefore that I release to you the King of the Jews?'","M":"'But it is your custom for me to release to you one prisoner at the time of the Passover. Do you want me to release the king of the Jews?'","T":"'But you have a Passover custom that I release one prisoner for you. Do you want me to release to you the King of the Jews?'"},
    "40": {"L":"Therefore they cried out again, saying: 'Not this man, but Barabbas!' Now Barabbas was a robber.","M":"They shouted back, 'No, not him! Give us Barabbas!' Now Barabbas had taken part in an uprising.","T":"They shouted back, 'Not him! Release Barabbas!' (Now Barabbas was a revolutionary.)"}
  },

  "19": {
    "1": {"L":"Then Pilate took Jesus and had him flogged.","M":"Then Pilate took Jesus and had him flogged.","T":"So Pilate had Jesus flogged."},
    "2": {"L":"And the soldiers wove a crown from thorns and placed it on his head, and put a purple robe on him.","M":"The soldiers twisted together a crown of thorns and put it on his head. They clothed him in a purple robe","T":"The soldiers twisted together a crown of thorns and put it on his head. They dressed him in a purple robe"},
    "3": {"L":"And they kept coming to him and saying: 'Hail, King of the Jews!' and were striking him with blows.","M":"and went up to him again and again, saying, 'Hail, king of the Jews!' And they slapped him in the face.","T":"and kept coming up to him, saying, 'Hail, king of the Jews!'—and slapping him in the face."},
    "4": {"L":"Pilate went out again and says to them: 'Look, I am bringing him out to you, so that you may know that I find no guilt in him.'","M":"Once more Pilate came out and said to the Jews gathered there, 'Look, I am bringing him out to you to let you know that I find no basis for a charge against him.'","T":"Pilate came back outside. 'I am bringing him out to you so you'll know I find no basis for any charge against him,' he said."},
    "5": {"L":"Therefore Jesus went out, wearing the crown of thorns and the purple robe. And Pilate says to them: 'Behold the man!'","M":"When Jesus came out wearing the crown of thorns and the purple robe, Pilate said to them, 'Here is the man!'","T":"Jesus came out, still wearing the crown of thorns and the purple robe. 'Look at this man!' Pilate said."},
    "6": {"L":"Therefore the chief priests and the officers, when they saw him, cried out, saying: 'Crucify! Crucify!' Pilate says to them: 'Take him yourselves and crucify him; for I find no guilt in him.'","M":"As soon as the chief priests and their officials saw him, they shouted, 'Crucify! Crucify!' But Pilate answered, 'You take him and crucify him. As for me, I find no basis for a charge against him.'","T":"When the chief priests and their officers saw him, they cried out, 'Crucify him! Crucify him!' Pilate replied, 'You take him and crucify him. I find no basis for charging him.'"},
    "7": {"L":"The Jews answered him: 'We have a law, and by that law he ought to die, because he made himself the Son of God.'","M":"The Jewish leaders insisted, 'We have a law, and according to that law he must die, because he claimed to be the Son of God.'","T":"The Jewish leaders replied, 'By our law he must die, because he claimed to be the Son of God.'"},
    "8": {"L":"Therefore when Pilate heard this word, he was more afraid,","M":"When Pilate heard this, he was even more afraid,","T":"When Pilate heard this, he was more frightened than ever."},
    "9": {"L":"and he entered the Praetorium again and says to Jesus: 'Where are you from?' But Jesus gave him no answer.","M":"and he went back inside the palace. 'Where do you come from?' he asked Jesus, but Jesus gave him no answer.","T":"He went back inside and asked Jesus, 'Where are you from?' But Jesus gave him no answer."},
    "10": {"L":"So Pilate says to him: 'Do you not speak to me? Do you not know that I have authority to release you, and I have authority to crucify you?'","M":"'Do you refuse to speak to me?' Pilate said. 'Don't you realize I have power either to free you or to crucify you?'","T":"'You won't talk to me?' Pilate demanded. 'Don't you know I have the authority to release you or to crucify you?'"},
    "11": {"L":"Jesus answered him: 'You would have no authority over me at all unless it had been given to you from above; for this reason the one who handed me over to you has greater sin.'","M":"Jesus answered, 'You would have no power over me if it were not given to you from above. Therefore the one who handed me over to you is guilty of a greater sin.'","T":"Jesus replied, 'You would have no power over me at all if it hadn't been given to you from above. That is why the man who handed me over to you is guilty of greater sin.'"},
    "12": {"L":"From this Pilate was seeking to release him; but the Jews cried out, saying: 'If you release this man, you are not a friend of Caesar; everyone who makes himself a king speaks against Caesar.'","M":"From then on, Pilate tried to set Jesus free, but the Jewish leaders kept shouting, 'If you let this man go, you are no friend of Caesar. Anyone who claims to be a king opposes Caesar.'","T":"Pilate wanted to release him, but the Jewish leaders shouted, 'If you release this man, you are no friend of Caesar! Anyone who claims to be king is an enemy of Caesar!'"},
    "13": {"L":"Therefore when Pilate heard these words, he brought Jesus out, and sat down on the judgment seat at a place called the Pavement—but in Hebrew, Gabbatha.","M":"When Pilate heard this, he brought Jesus out and sat down on the judge's seat at a place known as the Stone Pavement (which in Aramaic is Gabbatha).","T":"When Pilate heard this, he brought Jesus out and sat down on the judge's seat at the place known as the Stone Pavement—Gabbatha in Aramaic."},
    "14": {"L":"Now it was the Preparation of the Passover; the hour was about the sixth. And he says to the Jews: 'Behold your King!'","M":"It was the day of Preparation of the Passover; it was about noon. 'Here is your king,' Pilate said to the Jews.","T":"It was the day of Preparation for the Passover, about noon. Pilate said to the Jewish people, 'Look—here is your king!'"},
    "15": {"L":"Therefore they cried out: 'Away! Away! Crucify him!' Pilate says to them: 'Shall I crucify your King?' The chief priests answered: 'We have no king but Caesar.'","M":"But they shouted, 'Take him away! Take him away! Crucify him!' 'Shall I crucify your king?' Pilate asked. 'We have no king but Caesar,' the chief priests answered.","T":"They shouted, 'Away with him! Away with him! Crucify him!' 'Shall I crucify your king?' Pilate asked. 'We have no king but Caesar,' the chief priests replied."},
    "16": {"L":"Therefore he handed him over to them to be crucified. So they took Jesus,","M":"Finally Pilate handed him over to them to be crucified. So the soldiers took charge of Jesus.","T":"So Pilate handed Jesus over to be crucified. The soldiers took him away."},
    "17": {"L":"and carrying his own cross, he went out to the place called the Place of a Skull, which is called in Hebrew Golgotha.","M":"Carrying his own cross, he went out to the place of the Skull (which in Aramaic is called Golgotha).","T":"Jesus carried his own cross out to the Place of the Skull—called Golgotha in Aramaic."},
    "18": {"L":"There they crucified him, and with him two others—one on either side, and Jesus in the middle.","M":"There they crucified him, and with him two others—one on each side and Jesus in the middle.","T":"There they crucified him, along with two others—one on each side, with Jesus in the middle."},
    "19": {"L":"Now Pilate also wrote a notice and put it on the cross. It was written: 'JESUS THE NAZARENE, THE KING OF THE JEWS.'","M":"Pilate had a notice prepared and fastened to the cross. It read: JESUS OF NAZARETH, THE KING OF THE JEWS.","T":"Pilate had a sign made and attached to the cross. It read: JESUS OF NAZARETH, THE KING OF THE JEWS."},
    "20": {"L":"Many of the Jews therefore read this notice, because the place where Jesus was crucified was near the city; and it was written in Hebrew, in Latin, in Greek.","M":"Many of the Jews read this sign, for the place where Jesus was crucified was near the city, and the sign was written in Aramaic, Latin and Greek.","T":"Many Jewish people read this sign, because the place of crucifixion was near Jerusalem, and the notice was written in Aramaic, Latin, and Greek."},
    "21": {"L":"Therefore the chief priests of the Jews were saying to Pilate: 'Do not write: The King of the Jews; but that he said: I am King of the Jews.'","M":"The chief priests of the Jews protested to Pilate, 'Do not write The King of the Jews, but that this man claimed to be king of the Jews.'","T":"The chief priests protested to Pilate, 'Don't write The King of the Jews! Write that he claimed to be King of the Jews.'"},
    "22": {"L":"Pilate answered: 'What I have written, I have written.'","M":"Pilate answered, 'What I have written, I have written.'","T":"Pilate replied, 'What I have written, I have written.'"},
    "23": {"L":"The soldiers therefore, when they crucified Jesus, took his garments and made four parts, a part for each soldier; also the tunic. Now the tunic was seamless, woven throughout from the top.","M":"When the soldiers crucified Jesus, they took his clothes, dividing them into four shares, one for each of them, with the undergarment remaining. This garment was seamless, woven in one piece from top to bottom.","T":"After the soldiers crucified Jesus, they divided his clothes into four shares—one for each soldier. But his tunic was woven as one seamless piece from top to bottom."},
    "24": {"L":"So they said to one another: 'Let us not tear it, but cast lots for it to see whose it will be.' This was so that the scripture might be fulfilled: 'They divided my garments among themselves, and for my clothing they cast lots.'","M":"'Let's not tear it,' they said to one another. 'Let's decide by lot who will get it.' This happened that the scripture might be fulfilled that said, 'They divided my clothes among them and cast lots for my garment.' So this is what the soldiers did.","T":"'Let's not tear it,' the soldiers said. 'Let's throw dice to see who gets it.' This fulfilled the scripture: They divided my clothes among them and threw dice for my garment."},
    "25": {"L":"Now there stood by the cross of Jesus his mother, and his mother's sister, Mary the wife of Clopas, and Mary Magdalene.","M":"Near the cross of Jesus stood his mother, his mother's sister, Mary the wife of Clopas, and Mary Magdalene.","T":"Standing near the cross were Jesus' mother, her sister, Mary the wife of Clopas, and Mary Magdalene."},
    "26": {"L":"Therefore when Jesus saw his mother and the disciple whom he loved standing nearby, he says to his mother: 'Woman, behold your son!'","M":"When Jesus saw his mother there, and the disciple whom he loved standing nearby, he said to her, 'Woman, here is your son,'","T":"Jesus saw his mother and the disciple he loved standing nearby. He said to her, 'Dear woman, here is your son.'"},
    "27": {"L":"Then he says to the disciple: 'Behold, your mother!' And from that hour the disciple took her into his own home.","M":"and to the disciple, 'Here is your mother.' From that time on, this disciple took her into his own home.","T":"And to the disciple he said, 'Here is your mother.' From that moment, that disciple took her into his own home."},
    "28": {"L":"After this, Jesus knowing that all things had now been finished, so that the scripture might be fulfilled, says: 'I thirst.'","M":"Later, knowing that everything had now been finished, and so that Scripture would be fulfilled, Jesus said, 'I am thirsty.'","T":"Jesus knew that everything was now complete. To fulfill the scripture, he said, 'I am thirsty.'"},
    "29": {"L":"A jar full of sour wine was standing there; so they put a sponge full of the sour wine on a hyssop stalk and brought it to his mouth.","M":"A jar of wine vinegar was there, so they soaked a sponge in it, put the sponge on a stalk of the hyssop plant, and lifted it to Jesus' lips.","T":"A jar of sour wine was nearby, so they soaked a sponge in it, put it on a hyssop stalk, and held it up to his lips."},
    "30": {"L":"Therefore when Jesus received the sour wine, he said: 'It is finished!' And bowing his head, he gave up his spirit.","M":"When he had received the drink, Jesus said, 'It is finished.' With that, he bowed his head and gave up his spirit.","T":"When Jesus had tasted it, he said, 'It is finished!' Then he bowed his head and released his spirit."},
    "31": {"L":"The Jews therefore, since it was the Preparation, so that the bodies would not remain on the cross on the Sabbath—for that Sabbath was a great day—asked Pilate that their legs might be broken and that they might be taken away.","M":"Now it was the day of Preparation, and the next day was to be a special Sabbath. Because the Jewish leaders did not want the bodies left on the crosses during the Sabbath, they asked Pilate to have the legs broken and the bodies taken down.","T":"It was the day of Preparation, and the following Sabbath was a special holy day. So the Jewish leaders asked Pilate to have the men's legs broken to hasten death and have the bodies removed."},
    "32": {"L":"So the soldiers came and broke the legs of the first man and of the other who was crucified with him.","M":"The soldiers therefore came and broke the legs of the first man who had been crucified with Jesus, and then those of the other.","T":"The soldiers came and broke the legs of the two men crucified alongside Jesus."},
    "33": {"L":"But when they came to Jesus, as they saw that he was already dead, they did not break his legs.","M":"But when they came to Jesus and found that he was already dead, they did not break his legs.","T":"But when they came to Jesus and saw that he was already dead, they didn't break his legs."},
    "34": {"L":"But one of the soldiers pierced his side with a spear, and immediately blood and water came out.","M":"Instead, one of the soldiers pierced Jesus' side with a spear, bringing a sudden flow of blood and water.","T":"Instead, one of the soldiers plunged a spear into Jesus' side, and blood and water immediately flowed out."},
    "35": {"L":"And he who has seen has borne witness, and his testimony is true; and he knows that he says true things, so that you also may believe.","M":"The man who saw it has given testimony, and his testimony is true. He knows that he tells the truth, and he testifies so that you also may believe.","T":"The one who saw this has testified about it, and his testimony is reliable. He knows he is telling the truth so you also can believe."},
    "36": {"L":"For these things happened so that the scripture might be fulfilled: 'Not a bone of his will be broken.'","M":"These things happened so that the scripture would be fulfilled: 'Not one of his bones will be broken,'","T":"These things happened to fulfill the scripture: Not one of his bones will be broken."},
    "37": {"L":"And again another scripture says: 'They will look upon the one whom they have pierced.'","M":"and, as another scripture says, 'They will look on the one they have pierced.'","T":"And another scripture says: They will look on the one they have pierced."},
    "38": {"L":"After these things, Joseph of Arimathea—being a disciple of Jesus, but secretly for fear of the Jews—asked Pilate that he might take the body of Jesus. And Pilate permitted it. Therefore he came and took the body of Jesus.","M":"Later, Joseph of Arimathea asked Pilate for the body of Jesus. Now Joseph was a disciple of Jesus, but secretly because he feared the Jewish leaders. With Pilate's permission, he came and took the body away.","T":"After this, Joseph of Arimathea—a secret disciple of Jesus who feared the Jewish leaders—asked Pilate for permission to take Jesus' body. Pilate agreed, and Joseph came and took it away."},
    "39": {"L":"And Nicodemus also came—the one who had come to him earlier at night—bringing a mixture of myrrh and aloes, about a hundred pounds.","M":"He was accompanied by Nicodemus, the man who earlier had visited Jesus at night. Nicodemus brought a mixture of myrrh and aloes, about seventy-five pounds.","T":"Nicodemus came too—the same man who had visited Jesus under cover of darkness. He brought a mixture of myrrh and aloes, about seventy-five pounds of it."},
    "40": {"L":"So they took the body of Jesus and bound it in linen cloths with the spices, as is the burial custom of the Jews.","M":"Taking Jesus' body, the two of them wrapped it, with the spices, in strips of linen. This was in accordance with Jewish burial customs.","T":"The two of them wrapped Jesus' body in linen strips along with the spices, according to Jewish burial customs."},
    "41": {"L":"Now in the place where he was crucified there was a garden, and in the garden a new tomb in which no one had yet been laid.","M":"At the place where Jesus was crucified, there was a garden, and in the garden a new tomb, in which no one had ever been laid.","T":"Near the place of crucifixion there was a garden with a new tomb—one that had never been used."},
    "42": {"L":"Therefore on account of the Preparation of the Jews, since the tomb was nearby, they laid Jesus there.","M":"Because it was the Jewish day of Preparation and since the tomb was nearby, they laid Jesus there.","T":"Because it was the Jewish day of Preparation and the tomb was close by, they placed Jesus there."}
  },

  "20": {
    "1": {"L":"Now on the first day of the week, Mary Magdalene comes to the tomb early, while it was still dark, and sees the stone had been removed from the tomb.","M":"Early on the first day of the week, while it was still dark, Mary Magdalene went to the tomb and saw that the stone had been removed from the entrance.","T":"Early Sunday morning, while it was still dark, Mary Magdalene went to the tomb and saw that the stone had been rolled away from the entrance."},
    "2": {"L":"Therefore she runs and comes to Simon Peter and to the other disciple whom Jesus loved, and says to them: 'They have taken the Lord out of the tomb, and we do not know where they have laid him.'","M":"So she came running to Simon Peter and the other disciple, the one Jesus loved, and said, 'They have taken the Lord out of the tomb, and we don't know where they have put him!'","T":"She ran to Simon Peter and the other disciple—the one Jesus loved—and said, 'They have taken the Lord out of the tomb! We don't know where they've put him!'"},
    "3": {"L":"Therefore Peter and the other disciple went out and were going to the tomb.","M":"So Peter and the other disciple started for the tomb.","T":"Peter and the other disciple ran for the tomb."},
    "4": {"L":"And they were both running together; and the other disciple ran ahead faster than Peter and came to the tomb first.","M":"Both were running, but the other disciple outran Peter and reached the tomb first.","T":"They ran together, but the other disciple outran Peter and arrived at the tomb first."},
    "5": {"L":"And stooping down, he saw the linen cloths lying; yet he did not go in.","M":"He bent over and looked in at the strips of linen lying there but did not go in.","T":"He bent down, looked in, and saw the linen wrappings lying there—but he didn't go in."},
    "6": {"L":"Then Simon Peter also comes following him, and entered the tomb; and he sees the linen cloths lying there,","M":"Then Simon Peter came along behind him and went straight into the tomb. He saw the strips of linen lying there,","T":"Then Simon Peter arrived behind him and went straight into the tomb. He saw the linen strips lying there,"},
    "7": {"L":"and the cloth that had been on his head, not lying with the linen cloths but rolled up in a separate place.","M":"as well as the cloth that had been wrapped around Jesus' head. The cloth was still lying in its place, separate from the linen.","T":"as well as the cloth that had covered Jesus' head—but it was folded neatly in a place by itself."},
    "8": {"L":"Then the other disciple who had come to the tomb first also entered, and he saw and believed.","M":"Finally the other disciple, who had reached the tomb first, also went inside. He saw and believed.","T":"Then the other disciple went in too. He saw and believed."},
    "9": {"L":"For they did not yet understand the scripture, that he must rise from the dead.","M":"(They still did not understand from Scripture that Jesus had to rise from the dead.)","T":"(They hadn't yet understood the scripture that he must rise from the dead.)"},
    "10": {"L":"So the disciples went back to themselves.","M":"Then the disciples went back to where they were staying.","T":"Then the disciples went back home."},
    "11": {"L":"But Mary was standing outside the tomb weeping. As she wept therefore, she stooped down to look into the tomb;","M":"Now Mary stood outside the tomb crying. As she wept, she bent over to look into the tomb","T":"Mary stood outside the tomb weeping. As she wept, she bent down to look inside."},
    "12": {"L":"and she sees two angels in white, sitting—one at the head and one at the feet—where the body of Jesus had been lying.","M":"and saw two angels in white, seated where Jesus' body had been, one at the head and the other at the foot.","T":"She saw two angels in white sitting where Jesus' body had been—one at the head and one at the feet."},
    "13": {"L":"And they say to her: 'Woman, why are you weeping?' She says to them: 'They have taken my Lord, and I do not know where they have laid him.'","M":"They asked her, 'Woman, why are you crying?' 'They have taken my Lord away,' she said, 'and I don't know where they have put him.'","T":"They asked her, 'Why are you crying?' 'Because they have taken my Lord away,' she said, 'and I don't know where they've put him.'"},
    "14": {"L":"Having said this, she turned around and sees Jesus standing there, and did not know that it was Jesus.","M":"At this, she turned around and saw Jesus standing there, but she did not realize that it was Jesus.","T":"As she said this, she turned around and saw Jesus standing there—but she didn't recognize him."},
    "15": {"L":"Jesus says to her: 'Woman, why are you weeping? Whom are you seeking?' Thinking he was the gardener, she says to him: 'Lord, if you have carried him away, tell me where you have put him, and I will take him away.'","M":"He asked her, 'Woman, why are you crying? Who is it you are looking for?' Thinking he was the gardener, she said, 'Sir, if you have carried him away, tell me where you have put him, and I will get him.'","T":"'Why are you crying? Who are you looking for?' Jesus asked. Thinking he was the gardener, she said, 'Sir, if you've taken him away, tell me where you put him and I will get him.'"},
    "16": {"L":"Jesus says to her: 'Mary!' She turned around and says to him in Hebrew: 'Rabboni!'—which means Teacher.","M":"Jesus said to her, 'Mary.' She turned toward him and cried out in Aramaic, 'Rabboni!' (which means Teacher).","T":"Jesus simply said, 'Mary.' She spun around and cried out in Aramaic, 'Rabboni!'—which means Teacher."},
    "17": {"L":"Jesus says to her: 'Do not cling to me, for I have not yet ascended to the Father; but go to my brothers and say to them: I am ascending to my Father and your Father, and my God and your God.'","M":"Jesus said, 'Do not hold on to me, for I have not yet ascended to the Father. Go instead to my brothers and tell them, I am ascending to my Father and your Father, to my God and your God.'","T":"Jesus told her, 'Don't try to hold on to me—I haven't yet ascended to the Father. But go find my brothers and tell them: I am ascending to my Father—who is also your Father—to my God—who is also your God.'"},
    "18": {"L":"Mary Magdalene comes announcing to the disciples: 'I have seen the Lord,' and that he had said these things to her.","M":"Mary Magdalene went to the disciples with the news: 'I have seen the Lord!' And she told them that he had said these things to her.","T":"Mary Magdalene went to the disciples with the news: 'I have seen the Lord!' And she told them what he had said to her."},
    "19": {"L":"Therefore when it was evening on that day, the first day of the week, and when the doors were locked where the disciples were, for fear of the Jews, Jesus came and stood in their midst and says to them: 'Peace to you.'","M":"On the evening of that first day of the week, when the disciples were together, with the doors locked for fear of the Jewish leaders, Jesus came and stood among them and said, 'Peace be with you!'","T":"That Sunday evening, the disciples were gathered behind locked doors because they feared the Jewish leaders. Suddenly Jesus appeared and stood among them. 'Peace be with you!' he said."},
    "20": {"L":"And having said this, he showed them his hands and his side. The disciples therefore rejoiced, seeing the Lord.","M":"After he said this, he showed them his hands and side. The disciples were overjoyed when they saw the Lord.","T":"Then he showed them his hands and his side. The disciples were overjoyed when they saw the Lord."},
    "21": {"L":"Therefore Jesus said to them again: 'Peace to you; just as the Father has sent me, so also I send you.'","M":"Again Jesus said, 'Peace be with you! As the Father has sent me, I am sending you.'","T":"He said again, 'Peace be with you. As the Father sent me, so I am sending you.'"},
    "22": {"L":"And having said this, he breathed on them and says to them: 'Receive the Holy Spirit.'","M":"And with that he breathed on them and said, 'Receive the Holy Spirit.'","T":"Then he breathed on them and said, 'Receive the Holy Spirit.'"},
    "23": {"L":"'If you forgive the sins of any, they are forgiven them; if you retain the sins of any, they are retained.'","M":"'If you forgive anyone's sins, their sins are forgiven; if you do not forgive them, they are not forgiven.'","T":"'If you forgive anyone's sins, they are forgiven. If you do not forgive them, they are not forgiven.'"},
    "24": {"L":"But Thomas, one of the twelve, called the Twin, was not with them when Jesus came.","M":"Now Thomas (also known as Didymus), one of the Twelve, was not with the disciples when Jesus came.","T":"Thomas—one of the twelve, nicknamed the Twin—was not present when Jesus appeared."},
    "25": {"L":"Therefore the other disciples were saying to him: 'We have seen the Lord!' But he said to them: 'Unless I see in his hands the mark of the nails, and put my finger into the mark of the nails, and put my hand into his side, I will certainly not believe.'","M":"So the other disciples told him, 'We have seen the Lord!' But he said to them, 'Unless I see the nail marks in his hands and put my finger where the nails were, and put my hand into his side, I will not believe.'","T":"The others told him, 'We have seen the Lord!' He replied, 'Unless I see the nail marks in his hands and put my finger in the holes, and put my hand into his side—I will not believe.'"},
    "26": {"L":"And after eight days his disciples were inside again, and Thomas was with them. Jesus comes, the doors being locked, and stood in their midst and said: 'Peace to you.'","M":"A week later his disciples were in the house again, and Thomas was with them. Though the doors were locked, Jesus came and stood among them and said, 'Peace be with you!'","T":"A week later, the disciples were together again—and this time Thomas was with them. Even though the doors were locked, Jesus came and stood among them. 'Peace be with you!' he said."},
    "27": {"L":"Then he says to Thomas: 'Put your finger here, and see my hands; and put out your hand and put it into my side; and do not be unbelieving, but believing.'","M":"Then he said to Thomas, 'Put your finger here; see my hands. Reach out your hand and put it into my side. Stop doubting and believe.'","T":"Then he turned to Thomas. 'Put your finger here—look at my hands. Reach out your hand and put it in my side. Stop doubting and believe!'"},
    "28": {"L":"Thomas answered and said to him: 'My Lord and my God!'","M":"Thomas said to him, 'My Lord and my God!'","T":"Thomas exclaimed, 'My Lord and my God!'"},
    "29": {"L":"Jesus says to him: 'Because you have seen me, you have believed. Blessed are those who have not seen and have believed.'","M":"Then Jesus told him, 'Because you have seen me, you have believed; blessed are those who have not seen and yet have believed.'","T":"Jesus replied, 'You believed because you saw me. Blessed are those who believe without seeing.'"},
    "30": {"L":"Therefore Jesus did many other signs in the presence of his disciples, which are not written in this book.","M":"Jesus performed many other signs in the presence of his disciples, which are not recorded in this book.","T":"Jesus performed many other miraculous signs in the presence of his disciples that are not recorded in this book."},
    "31": {"L":"But these are written so that you may believe that Jesus is the Christ, the Son of God, and that believing you may have life in his name.","M":"But these are written that you may believe that Jesus is the Messiah, the Son of God, and that by believing you may have life in his name.","T":"But these are written so that you will believe that Jesus is the Messiah, the Son of God—and that by believing you will have life in his name."}
  },

  "21": {
    "1": {"L":"After these things Jesus revealed himself again to the disciples at the Sea of Tiberias. And he revealed himself in this manner:","M":"Afterward Jesus appeared again to his disciples, by the Sea of Galilee. It happened this way:","T":"Later, Jesus revealed himself again to his disciples by the Sea of Tiberias. Here's how it happened:"},
    "2": {"L":"Simon Peter, Thomas called the Twin, Nathanael who was from Cana of Galilee, and the sons of Zebedee, and two others of his disciples were together.","M":"Simon Peter, Thomas (also known as Didymus), Nathanael from Cana in Galilee, the sons of Zebedee, and two other disciples were together.","T":"Simon Peter, Thomas the Twin, Nathanael from Cana in Galilee, James and John, and two other disciples were together."},
    "3": {"L":"Simon Peter says to them: 'I am going fishing.' They say to him: 'We are also coming with you.' They went out and got into the boat, and in that night they caught nothing.","M":"'I'm going out to fish,' Simon Peter told them, and they said, 'We'll go with you.' So they went out and got into the boat, but that night they caught nothing.","T":"'I'm going fishing,' Simon Peter announced. 'We'll come too,' the others said. So they went out and fished all night but caught nothing."},
    "4": {"L":"Now when morning had already come, Jesus stood on the shore; yet the disciples did not know that it was Jesus.","M":"Early in the morning, Jesus stood on the shore, but the disciples did not realize that it was Jesus.","T":"At dawn Jesus was standing on the shore, but the disciples didn't recognize him."},
    "5": {"L":"Therefore Jesus says to them: 'Children, do you have any fish?' They answered him: 'No.'","M":"He called out to them, 'Friends, haven't you any fish?' 'No,' they answered.","T":"He called out, 'Friends, did you catch anything?' 'Nothing,' they replied."},
    "6": {"L":"And he said to them: 'Cast the net on the right side of the boat, and you will find some.' Therefore they cast it, and they were no longer able to drag it in because of the abundance of fish.","M":"He said, 'Throw your net on the right side of the boat and you will find some.' When they did, they were unable to haul the net in because of the large number of fish.","T":"'Throw your net on the right side of the boat,' he told them. They did, and suddenly they couldn't haul it in because there were so many fish."},
    "7": {"L":"Therefore that disciple whom Jesus loved says to Peter: 'It is the Lord!' Therefore Simon Peter, having heard that it is the Lord, wrapped his outer garment around himself—for he was stripped—and threw himself into the sea.","M":"Then the disciple whom Jesus loved said to Peter, 'It is the Lord!' As soon as Simon Peter heard him say, 'It is the Lord,' he wrapped his outer garment around him (for he had taken it off) and jumped into the water.","T":"The disciple Jesus loved said to Peter, 'It's the Lord!' When Simon Peter heard this, he put on his outer garment—he had been stripped for work—and plunged into the water."},
    "8": {"L":"But the other disciples came in the small boat, for they were not far from the land, but about two hundred cubits, dragging the net with the fish.","M":"The other disciples followed in the boat, towing the net full of fish, for they were not far from shore, about a hundred yards.","T":"The other disciples came in the boat, dragging the net full of fish—they were about a hundred yards from shore."},
    "9": {"L":"Therefore when they got out on the land, they see a charcoal fire there, with fish on it, and bread.","M":"When they landed, they saw a fire of burning coals there with fish on it, and some bread.","T":"When they got there, they saw a charcoal fire burning with fish cooking on it, and bread nearby."},
    "10": {"L":"Jesus says to them: 'Bring some of the fish that you caught just now.'","M":"Jesus said to them, 'Bring some of the fish you have just caught.'","T":"Jesus told them, 'Bring some of the fish you just caught.'"},
    "11": {"L":"So Simon Peter went aboard and drew the net to land, full of large fish—one hundred fifty-three; and though there were so many, the net was not torn.","M":"So Simon Peter climbed back into the boat and dragged the net ashore. It was full of large fish, 153, but even with so many the net was not torn.","T":"Simon Peter went aboard and dragged the net to shore. It was full of large fish—153 of them—yet the net didn't tear."},
    "12": {"L":"Jesus says to them: 'Come, have breakfast.' None of the disciples dared to ask him: 'Who are you?' knowing that it was the Lord.","M":"Jesus said to them, 'Come and have breakfast.' None of the disciples dared ask him, 'Who are you?' They knew it was the Lord.","T":"'Come and have breakfast,' Jesus told them. None of the disciples dared ask 'Who are you?'—they knew it was the Lord."},
    "13": {"L":"Jesus comes and takes the bread and gives it to them, and likewise the fish.","M":"Jesus came, took the bread and gave it to them, and did the same with the fish.","T":"Jesus served them the bread and the fish."},
    "14": {"L":"This was now the third time Jesus was revealed to the disciples after being raised from the dead.","M":"This was now the third time Jesus appeared to his disciples after he was raised from the dead.","T":"This was the third time Jesus had appeared to his disciples since his resurrection."},
    "15": {"L":"So when they had eaten breakfast, Jesus says to Simon Peter: 'Simon, son of John, do you love me more than these?' He says to him: 'Yes, Lord; you know that I am fond of you.' He says to him: 'Feed my lambs.'","M":"When they had finished eating, Jesus said to Simon Peter, 'Simon son of John, do you love me more than these?' 'Yes, Lord,' he said, 'you know that I love you.' Jesus said, 'Feed my lambs.'","T":"After breakfast, Jesus said to Simon Peter, 'Simon, son of John, do you love me more than these others do?' 'Yes, Lord,' Peter replied. 'You know I love you.' Jesus said, 'Then feed my lambs.'"},
    "16": {"L":"He says to him a second time: 'Simon, son of John, do you love me?' He says to him: 'Yes, Lord; you know that I am fond of you.' He says to him: 'Shepherd my sheep.'","M":"Again Jesus said, 'Simon son of John, do you love me?' He answered, 'Yes, Lord, you know that I love you.' Jesus said, 'Take care of my sheep.'","T":"Jesus asked again, 'Simon, son of John, do you love me?' 'Yes, Lord, you know I love you,' Peter said. Jesus replied, 'Take care of my sheep.'"},
    "17": {"L":"He says to him the third time: 'Simon, son of John, are you fond of me?' Peter was grieved because he said to him the third time: 'Are you fond of me?' And he said to him: 'Lord, you know all things; you know that I am fond of you.' Jesus says to him: 'Feed my sheep.'","M":"The third time he said to him, 'Simon son of John, do you love me?' Peter was hurt because Jesus asked him the third time, 'Do you love me?' He said, 'Lord, you know all things; you know that I love you.' Jesus said, 'Feed my sheep.'","T":"A third time Jesus asked, 'Simon, son of John, do you love me?' Peter was hurt that Jesus asked the same question three times. 'Lord, you know everything,' he said. 'You know I love you.' Jesus said, 'Then feed my sheep.'"},
    "18": {"L":"'Truly, truly I say to you, when you were younger you used to dress yourself and walk wherever you wished; but when you grow old, you will stretch out your hands, and another will dress you and bring you where you do not wish.'","M":"'Truly, truly, I tell you, when you were younger you dressed yourself and went where you wanted; but when you are old you will stretch out your hands, and someone else will dress you and lead you where you do not want to go.'","T":"'I tell you the truth: when you were young, you dressed yourself and went wherever you wanted. But when you are old, you will hold out your hands and someone else will take you where you don't want to go.'"},
    "19": {"L":"Now this he said, signifying by what kind of death he would glorify God. And having said this he says to him: 'Follow me.'","M":"Jesus said this to indicate the kind of death by which Peter would glorify God. Then he said to him, 'Follow me!'","T":"Jesus said this to indicate the kind of death by which Peter would honor God. Then he said simply, 'Follow me.'"},
    "20": {"L":"Peter, having turned, sees the disciple whom Jesus loved following—who was also the one who had reclined on his chest at the supper and said: 'Lord, who is the one who is betraying you?'","M":"Peter turned and saw that the disciple whom Jesus loved was following them. (This was the one who had leaned back against Jesus at the supper and had said, 'Lord, who is going to betray you?')","T":"Peter turned and saw the disciple Jesus loved following them—the one who had leaned close to Jesus at the supper and asked, 'Lord, who is going to betray you?'"},
    "21": {"L":"So Peter seeing this one says to Jesus: 'Lord, and what about this man?'","M":"When Peter saw him, he asked, 'Lord, what about him?'","T":"When Peter saw him, he asked, 'Lord, what about this man?'"},
    "22": {"L":"Jesus says to him: 'If I want him to remain until I come, what is that to you? You follow me!'","M":"Jesus answered, 'If I want him to remain alive until I return, what is that to you? You must follow me.'","T":"Jesus replied, 'What if I want him to remain until I come back? That's not your concern. You just follow me.'"},
    "23": {"L":"So this word went out among the brothers that that disciple would not die; yet Jesus had not said to him that he would not die, but: 'If I want him to remain until I come, what is that to you?'","M":"Because of this, the rumor spread among the believers that this disciple would not die. But Jesus did not say that he would not die; he only said, 'If I want him to remain alive until I return, what is that to you?'","T":"So a rumor spread among the believers that this disciple would not die. But Jesus hadn't said that—he only said, 'What if I want him to remain until I come back? That's not your concern.'"},
    "24": {"L":"This is the disciple who is testifying about these things and who has written these things; and we know that his testimony is true.","M":"This is the disciple who testifies to these things and who wrote them down. We know that his testimony is true.","T":"This is the disciple who is testifying to these events and who actually wrote them down. We know that what he says is true."},
    "25": {"L":"And there are also many other things that Jesus did, which, if they were to be written one by one, I suppose the world itself would not contain the books that would be written.","M":"Jesus did many other things as well. If every one of them were written down, I suppose that even the whole world would not have room for the books that would be written.","T":"There are many other things Jesus did. If every one of them were written down, I think the whole world couldn't contain all the books that would need to be written."}
  }
}

def merge_tier(existing, new_data, tier_key):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, tiers in verses.items():
            existing[ch][v] = tiers[tier_key]

for tier, key in [('literal','L'), ('mediating','M'), ('thought','T')]:
    data = load(tier, 'john')
    merge_tier(data, JOHN, key)
    save(tier, 'john', data)

print('\nJohn 16–21 written. Chapters covered:', sorted(JOHN.keys(), key=int))
